//! Go tick converters (`sdks/go/tick_converters.go`) + public tick structs
//! (`sdks/go/tick_structs.go`).
//!
//! Public Go tick types + the `RightStr` helper + `Greeks` struct live in
//! `tick_structs.go`. The C-mirror (FFI) structs live in
//! `tick_ffi_mirrors.go` (hand-written, not emitted here).

use std::fmt::Write as _;

use super::schema::{Schema, TickTypeDef};
use super::sorted_type_names;

pub(super) fn render_go_tick_converters(schema: &Schema) -> String {
    let mut out = String::new();
    // Go spec header: `^// Code generated .* DO NOT EDIT\.$` — see
    // https://golang.org/s/generatedcode. Required for go vet / gofmt /
    // staticcheck to recognize this as machine-generated. Non-Go
    // emitters keep the uniform `@generated` form.
    out.push_str("// Code generated by build.rs from tick_schema.toml; DO NOT EDIT.\n\n");
    out.push_str("package thetadatadx\n\n");
    out.push_str("/*\n#include \"ffi_bridge.h\"\n*/\nimport \"C\"\n\n");
    out.push_str("import \"unsafe\"\n\n");
    for type_name in sorted_type_names(schema) {
        let def = &schema.types[type_name];
        out.push_str(&render_go_tick_converter(type_name, def));
        out.push('\n');
    }
    out
}

fn render_go_tick_converter(type_name: &str, def: &TickTypeDef) -> String {
    let mut out = String::new();
    let (func_name, arr_type, ffi_type, public_type) = match type_name {
        "EodTick" => ("convertEodTicks", "C.TdxTickArray", "cEodTick", "EodTick"),
        "OhlcTick" => (
            "convertOhlcTicks",
            "C.TdxTickArray",
            "cOhlcTick",
            "OhlcTick",
        ),
        "TradeTick" => (
            "convertTradeTicks",
            "C.TdxTickArray",
            "cTradeTick",
            "TradeTick",
        ),
        "QuoteTick" => (
            "convertQuoteTicks",
            "C.TdxTickArray",
            "cQuoteTick",
            "QuoteTick",
        ),
        "TradeQuoteTick" => (
            "convertTradeQuoteTicks",
            "C.TdxTickArray",
            "cTradeQuoteTick",
            "TradeQuoteTick",
        ),
        "OpenInterestTick" => (
            "convertOpenInterestTicks",
            "C.TdxTickArray",
            "cOpenInterestTick",
            "OpenInterestTick",
        ),
        "MarketValueTick" => (
            "convertMarketValueTicks",
            "C.TdxTickArray",
            "cMarketValueTick",
            "MarketValueTick",
        ),
        "GreeksTick" => (
            "convertGreeksTicks",
            "C.TdxTickArray",
            "cGreeksTick",
            "GreeksTick",
        ),
        "IvTick" => ("convertIvTicks", "C.TdxTickArray", "cIvTick", "IVTick"),
        "PriceTick" => (
            "convertPriceTicks",
            "C.TdxTickArray",
            "cPriceTick",
            "PriceTick",
        ),
        "CalendarDay" => (
            "convertCalendarDays",
            "C.TdxTickArray",
            "cCalendarDay",
            "CalendarDay",
        ),
        "InterestRateTick" => (
            "convertInterestRateTicks",
            "C.TdxTickArray",
            "cInterestRateTick",
            "InterestRateTick",
        ),
        "OptionContract" => (
            "convertOptionContracts",
            "C.TdxOptionContractArray",
            "cOptionContract",
            "OptionContract",
        ),
        other => panic!("unsupported Go tick converter type: {other}"),
    };

    writeln!(out, "func {func_name}(arr {arr_type}) []{public_type} {{").unwrap();
    out.push_str("    if arr.data == nil || arr.len == 0 {\n");
    out.push_str("        return nil\n");
    out.push_str("    }\n");
    out.push_str("    n := int(arr.len)\n");
    writeln!(out, "    src := unsafe.Slice((*{ffi_type})(arr.data), n)").unwrap();
    writeln!(out, "    result := make([]{public_type}, n)").unwrap();
    out.push_str("    for i, t := range src {\n");
    if type_name == "OptionContract" {
        out.push_str("        root := \"\"\n");
        out.push_str("        if t.Root != 0 {\n");
        out.push_str("            root = C.GoString((*C.char)(unsafe.Pointer(t.Root)))\n");
        out.push_str("        }\n");
    }
    writeln!(out, "        result[i] = {public_type}{{").unwrap();
    for column in &def.columns {
        let public_field = go_public_field_name(type_name, &column.field);
        let source_expr = go_source_expr(type_name, &column.field, &column.r#type);
        writeln!(out, "            {public_field}: {source_expr},").unwrap();
    }
    if type_name == "QuoteTick" {
        out.push_str("            Midpoint: t.Midpoint,\n");
    }
    if def.contract_id {
        out.push_str("            Expiration: t.Expiration,\n");
        out.push_str("            Strike: t.Strike,\n");
        out.push_str("            Right: RightStr(t.Right),\n");
    }
    out.push_str("        }\n");
    out.push_str("    }\n");
    out.push_str("    return result\n");
    out.push_str("}\n");
    out
}

fn go_public_field_name(type_name: &str, field: &str) -> &'static str {
    match (type_name, field) {
        ("GreeksTick", "implied_volatility") => "IV",
        ("IvTick", "implied_volatility") => "IV",
        (_, "iv_error") => "IVError",
        ("MarketValueTick", "market_bid") => "MarketBid",
        ("MarketValueTick", "market_ask") => "MarketAsk",
        ("MarketValueTick", "market_price") => "MarketPrice",
        (_, "ms_of_day") => "MsOfDay",
        (_, "ms_of_day2") => "MsOfDay2",
        (_, "quote_ms_of_day") => "QuoteMsOfDay",
        (_, "ext_condition1") => "ExtCondition1",
        (_, "ext_condition2") => "ExtCondition2",
        (_, "ext_condition3") => "ExtCondition3",
        (_, "ext_condition4") => "ExtCondition4",
        (_, "condition_flags") => "ConditionFlags",
        (_, "price_flags") => "PriceFlags",
        (_, "volume_type") => "VolumeType",
        (_, "records_back") => "RecordsBack",
        (_, "bid_size") => "BidSize",
        (_, "bid_exchange") => "BidExchange",
        (_, "bid_condition") => "BidCondition",
        (_, "ask_size") => "AskSize",
        (_, "ask_exchange") => "AskExchange",
        (_, "ask_condition") => "AskCondition",
        (_, "open_interest") => "OpenInterest",
        (_, "market_bid") => "MarketBid",
        (_, "market_ask") => "MarketAsk",
        (_, "market_price") => "MarketPrice",
        (_, "dual_delta") => "DualDelta",
        (_, "dual_gamma") => "DualGamma",
        (_, "is_open") => "IsOpen",
        other => Box::leak(go_pascal_case(other.1).into_boxed_str()),
    }
}

fn go_source_expr(type_name: &str, field: &str, kind: &str) -> String {
    let ffi_field = go_ffi_field_name(field);
    match (type_name, field, kind) {
        ("OptionContract", "root", "String") => "root".into(),
        ("OptionContract", "right", "i32") => "RightStr(t.Right)".into(),
        (_, "right", "i32") => "RightStr(t.Right)".into(),
        (_, "is_open", "i32") => "t.IsOpen != 0".into(),
        ("OptionContract", _, "i32") => format!("int(t.{ffi_field})"),
        (_, _, "i32") if field == "expiration" => format!("t.{ffi_field}"),
        (_, _, "i32") | (_, _, "eod_num") | (_, _, "eod_date") => format!("int(t.{ffi_field})"),
        (_, _, "i64")
        | (_, _, "eod_num64")
        | (_, _, "f64")
        | (_, _, "price")
        | (_, _, "eod_price") => format!("t.{ffi_field}"),
        (_, _, "String") => format!("t.{ffi_field}"),
        _ => panic!("unsupported Go source expression for {type_name}.{field}:{kind}"),
    }
}

fn go_ffi_field_name(field: &str) -> &'static str {
    match field {
        "implied_volatility" => "ImpliedVolatility",
        "iv_error" => "IvError",
        "market_bid" => "MarketBid",
        "market_ask" => "MarketAsk",
        "market_price" => "MarketPrice",
        "ms_of_day" => "MsOfDay",
        "ms_of_day2" => "MsOfDay2",
        "quote_ms_of_day" => "QuoteMsOfDay",
        "ext_condition1" => "ExtCondition1",
        "ext_condition2" => "ExtCondition2",
        "ext_condition3" => "ExtCondition3",
        "ext_condition4" => "ExtCondition4",
        "condition_flags" => "ConditionFlags",
        "price_flags" => "PriceFlags",
        "volume_type" => "VolumeType",
        "records_back" => "RecordsBack",
        "bid_size" => "BidSize",
        "bid_exchange" => "BidExchange",
        "bid_condition" => "BidCondition",
        "ask_size" => "AskSize",
        "ask_exchange" => "AskExchange",
        "ask_condition" => "AskCondition",
        "open_interest" => "OpenInterest",
        "dual_delta" => "DualDelta",
        "dual_gamma" => "DualGamma",
        "is_open" => "IsOpen",
        other => Box::leak(go_pascal_case(other).into_boxed_str()),
    }
}

fn go_pascal_case(value: &str) -> String {
    value
        .split('_')
        .filter(|segment| !segment.is_empty())
        .map(|segment| match segment {
            "iv" => "IV".to_string(),
            other => {
                let mut chars = other.chars();
                match chars.next() {
                    Some(first) => first.to_uppercase().to_string() + chars.as_str(),
                    None => String::new(),
                }
            }
        })
        .collect::<String>()
}

/// Map a tick_schema.toml column type to the Go public struct field type.
fn go_public_field_type(type_name: &str, field: &str, kind: &str) -> &'static str {
    // CalendarDay.is_open is a bool in the public API
    if type_name == "CalendarDay" && field == "is_open" {
        return "bool";
    }
    // OptionContract.right is i32 in the schema but exposed as string via RightStr()
    if type_name == "OptionContract" && field == "right" {
        return "string";
    }
    match kind {
        "i32" | "eod_num" | "eod_date" => "int",
        "i64" | "eod_num64" => "int64",
        "f64" | "price" | "eod_price" => "float64",
        "String" => "string",
        _ => panic!("unsupported Go public type for {type_name}.{field}:{kind}"),
    }
}

/// Map a tick_schema.toml column to the JSON tag for the Go public struct.
fn go_json_tag(field: &str) -> String {
    field.to_string()
}

pub(super) fn render_go_tick_structs(schema: &Schema) -> String {
    let mut out = String::new();
    // Go spec header (see render_go_tick_converters for the rationale).
    out.push_str("// Code generated by build.rs from tick_schema.toml; DO NOT EDIT.\n");
    out.push_str("//\n");
    out.push_str("// Public Go tick types, RightStr helper, and Greeks struct.\n");
    out.push_str("// C-mirror (FFI) structs live in tick_ffi_mirrors.go (hand-written).\n\n");
    out.push_str("package thetadatadx\n\n");

    // Emit public Go structs for each tick type
    for type_name in sorted_type_names(schema) {
        let def = &schema.types[type_name];
        out.push_str(&render_go_public_struct(type_name, def));
        out.push('\n');
    }

    // RightStr helper
    out.push_str("// RightStr converts the raw right code to a string.\n");
    out.push_str("// 67='C' (Call), 80='P' (Put), 0=\"\" (not set).\n");
    out.push_str("func RightStr(code int32) string {\n");
    out.push_str("\tswitch code {\n");
    out.push_str("\tcase 67:\n");
    out.push_str("\t\treturn \"C\"\n");
    out.push_str("\tcase 80:\n");
    out.push_str("\t\treturn \"P\"\n");
    out.push_str("\tdefault:\n");
    out.push_str("\t\treturn \"\"\n");
    out.push_str("\t}\n");
    out.push_str("}\n\n");

    // Greeks struct (offline utility, not a tick type — matches tdbe::Greeks)
    out.push_str("// Greeks holds the 22 Black-Scholes greeks + IV from all_greeks().\n");
    out.push_str("type Greeks struct {\n");
    for field in &[
        ("Value", "value"),
        ("Delta", "delta"),
        ("Gamma", "gamma"),
        ("Theta", "theta"),
        ("Vega", "vega"),
        ("Rho", "rho"),
        ("IV", "iv"),
        ("IVError", "iv_error"),
        ("Vanna", "vanna"),
        ("Charm", "charm"),
        ("Vomma", "vomma"),
        ("Veta", "veta"),
        ("Speed", "speed"),
        ("Zomma", "zomma"),
        ("Color", "color"),
        ("Ultima", "ultima"),
        ("D1", "d1"),
        ("D2", "d2"),
        ("DualDelta", "dual_delta"),
        ("DualGamma", "dual_gamma"),
        ("Epsilon", "epsilon"),
        ("Lambda", "lambda"),
    ] {
        writeln!(out, "\t{:9} float64 `json:\"{}\"`", field.0, field.1).unwrap();
    }
    out.push_str("}\n");

    out
}

fn render_go_public_struct(type_name: &str, def: &TickTypeDef) -> String {
    let mut out = String::new();
    let go_type = match type_name {
        "IvTick" => "IVTick",
        other => other,
    };
    writeln!(
        out,
        "// {} — {}",
        go_type,
        def.doc.lines().next().unwrap_or("")
    )
    .unwrap();
    writeln!(out, "type {go_type} struct {{").unwrap();

    for column in &def.columns {
        let public_field = go_public_field_name(type_name, &column.field);
        let go_type_str = go_public_field_type(type_name, &column.field, &column.r#type);
        let json_tag = go_json_tag(&column.name);
        writeln!(
            out,
            "\t{:14} {:<8} `json:\"{json_tag}\"`",
            public_field, go_type_str
        )
        .unwrap();
    }
    // QuoteTick gets a Midpoint field
    if type_name == "QuoteTick" {
        out.push_str("\tMidpoint       float64  `json:\"midpoint\"`\n");
    }
    // contract_id fields
    if def.contract_id {
        out.push_str("\tExpiration     int32    `json:\"expiration,omitempty\"`\n");
        out.push_str("\tStrike         float64  `json:\"strike,omitempty\"`\n");
        out.push_str("\tRight          string   `json:\"right,omitempty\"`\n");
    }
    out.push_str("}\n");
    out
}
